1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>Stockio Dashboard</title>
7	<script src="https://cdn.jsdelivr.net/npm/chart.js@4"></script>
8	<style>
9	  :root {
10	    --bg: #0f0f23;
11	    --card: #1a1a3e;
12	    --card-border: #2a2a5e;
13	    --text: #e0e0e0;
14	    --text-dim: #8888aa;
15	    --accent: #4fc3f7;
16	    --green: #4caf50;
17	    --red: #ef5350;
18	    --hold: #9e9e9e;
19	    --font: system-ui, -apple-system, sans-serif;
20	    --mono: 'JetBrains Mono', 'Fira Code', monospace;
21	  }
22	  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
23	  body { background: var(--bg); color: var(--text); font-family: var(--font); line-height: 1.5; padding: 0; }
24	  a { color: var(--accent); text-decoration: none; }
25	
26	  /* Header */
27	  .header {
28	    display: flex; align-items: center; gap: 16px; padding: 12px 24px;
29	    background: #12122a; border-bottom: 1px solid var(--card-border); flex-wrap: wrap;
30	  }
31	  .header-title { font-size: 1.4rem; font-weight: 700; color: #fff; }
32	  .version-badge {
33	    font-size: 0.7rem; background: var(--accent); color: #000; padding: 2px 8px;
34	    border-radius: 10px; font-weight: 600; vertical-align: middle;
35	  }
36	  .header-spacer { flex: 1; }
37	  .instance-toggle { display: flex; gap: 0; }
38	  .instance-btn {
39	    padding: 6px 18px; border: 1px solid var(--card-border); background: var(--card);
40	    color: var(--text-dim); cursor: pointer; font-size: 0.85rem; font-family: var(--font);
41	    transition: all 0.15s;
42	  }
43	  .instance-btn:first-child { border-radius: 6px 0 0 6px; }
44	  .instance-btn:last-child { border-radius: 0 6px 6px 0; }
45	  .instance-btn.active { background: var(--accent); color: #000; font-weight: 600; border-color: var(--accent); }
46	  .ctrl-btn {
47	    padding: 6px 16px; border: 1px solid var(--card-border); border-radius: 6px;
48	    background: var(--card); color: var(--text); cursor: pointer; font-size: 0.85rem;
49	    font-family: var(--font); transition: all 0.15s;
50	  }
51	  .ctrl-btn:hover { border-color: var(--accent); }
52	  .ctrl-btn.running { border-color: var(--red); color: var(--red); }
53	  .ctrl-btn.stopped { border-color: var(--green); color: var(--green); }
54	  .status-dot {
55	    width: 10px; height: 10px; border-radius: 50%; display: inline-block;
56	  }
57	  .status-dot.running { background: var(--green); box-shadow: 0 0 6px var(--green); }
58	  .status-dot.stopped { background: var(--red); }
59	  .status-dot.halted { background: #ff9800; box-shadow: 0 0 6px #ff9800; }
60	  .status-label { font-size: 0.85rem; color: var(--text-dim); margin-left: 4px; }
61	  .gear-btn {
62	    background: none; border: none; color: var(--text-dim); cursor: pointer;
63	    font-size: 1.3rem; padding: 4px 8px; transition: color 0.15s;
64	  }
65	  .gear-btn:hover { color: var(--accent); }
66	
67	  /* Main layout */
68	  .main { max-width: 1400px; margin: 0 auto; padding: 20px 24px; }
69	
70	  /* Cards row */
71	  .cards { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin-bottom: 20px; }
72	  .card {
73	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
74	    padding: 18px 20px;
75	  }
76	  .card-label { font-size: 0.78rem; color: var(--text-dim); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }
77	  .card-value { font-size: 1.6rem; font-weight: 700; font-family: var(--mono); }
78	  .card-value.positive { color: var(--green); }
79	  .card-value.negative { color: var(--red); }
80	
81	  /* Panels */
82	  .panel {
83	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
84	    padding: 18px 20px; margin-bottom: 20px;
85	  }
86	  .panel-title { font-size: 1rem; font-weight: 600; margin-bottom: 12px; color: #fff; }
87	
88	  /* Tables */
89	  .table-wrap { overflow-x: auto; }
90	  table { width: 100%; border-collapse: collapse; font-size: 0.82rem; }
91	  th { text-align: left; color: var(--text-dim); font-weight: 500; padding: 8px 10px;
92	       border-bottom: 1px solid var(--card-border); white-space: nowrap; font-size: 0.75rem;
93	       text-transform: uppercase; letter-spacing: 0.5px; }
94	  td { padding: 7px 10px; border-bottom: 1px solid #1e1e40; white-space: nowrap; font-family: var(--mono); font-size: 0.8rem; }
95	  tr:hover td { background: rgba(79, 195, 247, 0.04); }
96	  .dir-buy { color: var(--green); font-weight: 600; }
97	  .dir-sell { color: var(--red); font-weight: 600; }
98	  .dir-hold { color: var(--hold); }
99	  .scrollable-table { max-height: 340px; overflow-y: auto; }
100	
101	  /* Chart */
102	  .chart-container { position: relative; height: 280px; }
103	
104	  /* Bot log */
105	  .log-entry {
106	    border: 1px solid var(--card-border); border-radius: 8px; margin-bottom: 8px;
107	    overflow: hidden;
108	  }
109	  .log-header {
110	    display: flex; justify-content: space-between; align-items: center;
111	    padding: 10px 14px; cursor: pointer; background: rgba(255,255,255,0.02);
112	    transition: background 0.15s;
113	  }
114	  .log-header:hover { background: rgba(79, 195, 247, 0.05); }
115	  .log-cycle { font-weight: 600; font-family: var(--mono); font-size: 0.85rem; }
116	  .log-time { font-size: 0.75rem; color: var(--text-dim); }
117	  .log-arrow { color: var(--text-dim); transition: transform 0.2s; font-size: 0.8rem; }
118	  .log-arrow.open { transform: rotate(90deg); }
119	  .log-body { padding: 0 14px 12px; display: none; font-size: 0.82rem; }
120	  .log-body.open { display: block; }
121	  .log-stat { display: inline-block; margin-right: 18px; margin-top: 4px; }
122	  .log-stat-label { color: var(--text-dim); font-size: 0.75rem; }
123	  .log-stat-value { font-family: var(--mono); font-weight: 600; }
124	
125	  /* Engine footer */
126	  .engine-footer {
127	    display: flex; flex-wrap: wrap; gap: 24px; align-items: center;
128	    padding: 14px 20px; background: var(--card); border: 1px solid var(--card-border);
129	    border-radius: 10px; margin-bottom: 20px; font-size: 0.82rem;
130	  }
131	  .engine-stat-label { color: var(--text-dim); font-size: 0.72rem; text-transform: uppercase; }
132	  .engine-stat-value { font-family: var(--mono); font-weight: 600; }
133	  .halted-warning { color: #ff9800; font-weight: 600; }
134	
135	  /* Settings modal */
136	  .modal-overlay {
137	    display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.7);
138	    z-index: 1000; justify-content: center; align-items: center;
139	  }
140	  .modal-overlay.open { display: flex; }
141	  .modal {
142	    background: var(--card); border: 1px solid var(--card-border); border-radius: 12px;
143	    padding: 24px 28px; width: 460px; max-width: 95vw; max-height: 90vh; overflow-y: auto;
144	  }
145	  .modal-title { font-size: 1.1rem; font-weight: 700; color: #fff; margin-bottom: 18px; }
146	  .form-group { margin-bottom: 14px; }
147	  .form-label { display: block; font-size: 0.78rem; color: var(--text-dim); margin-bottom: 4px; text-transform: uppercase; letter-spacing: 0.3px; }
148	  .form-input {
149	    width: 100%; padding: 8px 12px; background: var(--bg); border: 1px solid var(--card-border);
150	    border-radius: 6px; color: var(--text); font-family: var(--mono); font-size: 0.85rem;
151	  }
152	  .form-input:focus { outline: none; border-color: var(--accent); }
153	  .modal-actions { display: flex; justify-content: flex-end; gap: 10px; margin-top: 20px; }
154	  .btn-save {
155	    padding: 8px 20px; background: var(--accent); color: #000; border: none;
156	    border-radius: 6px; cursor: pointer; font-weight: 600; font-family: var(--font); font-size: 0.85rem;
157	  }
158	  .btn-cancel {
159	    padding: 8px 20px; background: transparent; color: var(--text-dim); border: 1px solid var(--card-border);
160	    border-radius: 6px; cursor: pointer; font-family: var(--font); font-size: 0.85rem;
161	  }
162	  .btn-save:hover { filter: brightness(1.1); }
163	  .btn-cancel:hover { border-color: var(--text-dim); }
164	
165	  .no-data { color: var(--text-dim); font-style: italic; padding: 16px 0; font-size: 0.85rem; }
166	
167	  /* Bot Summary */
168	  .panel.summary-panel {
169	    border-left: 3px solid var(--accent);
170	    background: linear-gradient(135deg, var(--card) 0%, rgba(79,195,247,0.06) 100%);
171	  }
172	  .panel.summary-panel .summary-text {
173	    font-size: 1rem; line-height: 1.6; color: var(--text);
174	  }
175	
176	  /* Collapsible panels */
177	  .panel.collapsible .panel-title {
178	    cursor: pointer; user-select: none; display: flex; align-items: center; gap: 8px;
179	  }
180	  .panel.collapsible .panel-title .collapse-arrow {
181	    display: inline-block; font-size: 0.7rem; color: var(--text-dim);
182	    transition: transform 0.2s; flex-shrink: 0;
183	  }
184	  .panel.collapsible .panel-body { display: none; }
185	  .panel.collapsible.open .panel-body { display: block; }
186	  .panel.collapsible.open .panel-title .collapse-arrow { transform: rotate(90deg); }
187	
188	  /* Alert banner */
189	  #alertBanner {
190	    position: fixed; top: 0; left: 0; right: 0; z-index: 2000;
191	    padding: 12px 24px; font-size: 0.9rem; font-weight: 600;
192	    text-align: center; transform: translateY(-100%);
193	    transition: transform 0.35s ease; font-family: var(--font);
194	  }
195	  #alertBanner.visible { transform: translateY(0); }
196	  #alertBanner.trade { background: var(--green); color: #000; }
197	  #alertBanner.halted { background: #ff9800; color: #000; }
198	
199	  /* Responsive */
200	  @media (max-width: 900px) {
201	    .cards { grid-template-columns: repeat(2, 1fr); }
202	  }
203	  @media (max-width: 500px) {
204	    .cards { grid-template-columns: 1fr; }
205	    .header { padding: 10px 14px; gap: 10px; }
206	    .main { padding: 14px; }
207	  }
208	
209	  /* Scrollbar */
210	  ::-webkit-scrollbar { width: 6px; height: 6px; }
211	  ::-webkit-scrollbar-track { background: var(--bg); }
212	  ::-webkit-scrollbar-thumb { background: var(--card-border); border-radius: 3px; }
213	
214	  /* Sentiment combined scores */
215	  .sentiment-scores { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 12px; }
216	  .sentiment-chip { background: var(--bg); border: 1px solid var(--card-border); border-radius: 6px; padding: 6px 12px; font-family: var(--mono); font-size: 0.8rem; }
217	
218	  /* Trump headlines */
219	  .trump-badge { display: inline-block; background: #ff9800; color: #000; font-size: 0.7rem; font-weight: 700; padding: 2px 8px; border-radius: 10px; margin-left: 8px; vertical-align: middle; }
220	  .headline-list { display: flex; flex-direction: column; gap: 8px; }
221	  .headline-pill { background: var(--bg); border: 1px solid var(--card-border); border-radius: 8px; padding: 10px 14px; font-size: 0.82rem; line-height: 1.4; }
222	  .headline-time { font-size: 0.72rem; color: var(--text-dim); margin-top: 10px; }
223	
224	  /* Indicator gauges */
225	  .indicator-grid { display: flex; flex-direction: column; gap: 14px; }
226	  .indicator-row { display: flex; align-items: center; gap: 14px; flex-wrap: wrap; }
227	  .indicator-row-label { min-width: 110px; font-family: var(--mono); font-size: 0.8rem; font-weight: 600; color: #fff; flex-shrink: 0; }
228	  .gauge-group { display: flex; gap: 14px; flex-wrap: wrap; flex: 1; }
229	  .mini-gauge { display: flex; flex-direction: column; align-items: center; min-width: 90px; }
230	  .mini-gauge-label { font-size: 0.68rem; color: var(--text-dim); text-transform: uppercase; margin-bottom: 3px; }
231	  .gauge-bar { width: 80px; height: 8px; background: #1e1e40; border-radius: 4px; overflow: hidden; position: relative; }
232	  .gauge-fill { height: 100%; border-radius: 4px; transition: width 0.3s; }
233	  .gauge-value { font-family: var(--mono); font-size: 0.72rem; margin-top: 2px; }
234	  .gauge-bar-bipolar { width: 80px; height: 8px; background: #1e1e40; border-radius: 4px; position: relative; overflow: hidden; }
235	  .gauge-bar-bipolar .gauge-center { position: absolute; left: 50%; top: 0; width: 1px; height: 100%; background: var(--text-dim); }
236	  .gauge-bar-bipolar .gauge-fill-bi { position: absolute; top: 0; height: 100%; border-radius: 4px; transition: width 0.3s, left 0.3s; }
237	
238	  /* Decision waterfall */
239	  .waterfall-list { display: flex; flex-direction: column; gap: 6px; }
240	  .waterfall-item { border: 1px solid var(--card-border); border-radius: 8px; overflow: hidden; }
241	  .waterfall-header { display: flex; justify-content: space-between; align-items: center; padding: 8px 14px; cursor: pointer; background: rgba(255,255,255,0.02); transition: background 0.15s; }
242	  .waterfall-header:hover { background: rgba(79,195,247,0.05); }
243	  .waterfall-label { font-family: var(--mono); font-size: 0.85rem; font-weight: 600; }
244	  .waterfall-summary { display: flex; align-items: center; gap: 10px; font-size: 0.8rem; }
245	  .waterfall-arrow { color: var(--text-dim); transition: transform 0.2s; font-size: 0.8rem; }
246	  .waterfall-arrow.open { transform: rotate(90deg); }
247	  .waterfall-body { display: none; padding: 8px 14px 12px; }
248	  .waterfall-body.open { display: block; }
249	  .waterfall-bar-track { width: 100%; height: 20px; background: #1e1e40; border-radius: 4px; position: relative; overflow: hidden; display: flex; margin-bottom: 6px; }
250	  .waterfall-seg { height: 100%; display: flex; align-items: center; justify-content: center; font-size: 0.65rem; font-family: var(--mono); color: #fff; min-width: 2px; overflow: hidden; white-space: nowrap; }
251	  .waterfall-detail-row { display: flex; justify-content: space-between; font-size: 0.78rem; padding: 2px 0; border-bottom: 1px solid #1e1e40; }
252	  .waterfall-detail-row:last-child { border-bottom: none; }
253	
254	  /* Model learning */
255	  .model-layout { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
256	  .model-stats { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
257	  .model-stat-card { background: var(--bg); border: 1px solid var(--card-border); border-radius: 8px; padding: 12px; }
258	  .model-stat-card .card-label { font-size: 0.72rem; color: var(--text-dim); text-transform: uppercase; margin-bottom: 2px; }
259	  .model-stat-card .card-value { font-size: 1.1rem; font-weight: 700; font-family: var(--mono); }
260	  .streak-grid { display: flex; flex-wrap: wrap; gap: 4px; margin-top: 8px; }
261	  .streak-dot { width: 14px; height: 14px; border-radius: 3px; }
262	  .streak-dot.win { background: var(--green); }
263	  .streak-dot.loss { background: var(--red); }
264	  .cv-chart-container { height: 120px; margin-top: 12px; }
265	  .degraded-badge { display: inline-block; background: var(--red); color: #fff; font-size: 0.7rem; font-weight: 700; padding: 2px 8px; border-radius: 10px; }
266	
267	  /* Trade outcomes */
268	  .outcomes-top { display: grid; grid-template-columns: 1fr 160px; gap: 20px; align-items: center; margin-bottom: 16px; }
269	  .outcomes-big-stats { display: flex; gap: 24px; flex-wrap: wrap; }
270	  .big-stat { text-align: center; }
271	  .big-stat-value { font-size: 1.8rem; font-weight: 700; font-family: var(--mono); }
272	  .big-stat-label { font-size: 0.72rem; color: var(--text-dim); text-transform: uppercase; }
273	  .donut-container { position: relative; width: 120px; height: 120px; }
274	  .direction-bars { display: flex; gap: 20px; margin: 12px 0; }
275	  .dir-bar-group { flex: 1; }
276	  .dir-bar-label { font-size: 0.75rem; color: var(--text-dim); margin-bottom: 4px; }
277	  .dir-bar-track { height: 10px; background: #1e1e40; border-radius: 5px; overflow: hidden; }
278	  .dir-bar-fill { height: 100%; border-radius: 5px; transition: width 0.3s; }
279	  .recent-outcomes { display: flex; gap: 8px; flex-wrap: wrap; margin-top: 10px; }
280	  .outcome-item { display: flex; align-items: center; gap: 4px; background: var(--bg); border: 1px solid var(--card-border); border-radius: 6px; padding: 4px 10px; font-size: 0.75rem; font-family: var(--mono); }
281	  .outcome-icon { font-size: 0.9rem; }
282	  .outcome-icon.win { color: var(--green); }
283	  .outcome-icon.loss { color: var(--red); }
284	
285	  @media (max-width: 900px) {
286	    .model-layout { grid-template-columns: 1fr; }
287	    .outcomes-top { grid-template-columns: 1fr; }
288	  }
289	</style>
290	</head>
291	<body>
292	
293	<!-- Alert Banner -->
294	<div id="alertBanner"></div>
295	
296	<!-- Header -->
297	<div class="header">
298	  <span class="header-title">Stockio <span class="version-badge">{{ version|default('v0.1') }}</span></span>
299	  <div class="header-spacer"></div>
300	  <div class="instance-toggle">
